def CalcBeausoleilMorrisonMixedStableFloor(DeltaTemp: Float64, HydraulicDiameter: Float64, SurfTemp: Float64, SupplyAirTemp: Float64, AirChangeRate: Float64) -> Float64:
    var cofpow: Float64 = (0.6 * pow(abs(DeltaTemp) / HydraulicDiameter, 0.2)) ** 3 + ((SurfTemp - SupplyAirTemp) / abs(DeltaTemp) * (0.159 + 0.116 * pow(AirChangeRate, 0.8))) ** 3
    var Hc: Float64 = pow(abs(cofpow), 1.0 / 3.0)
